  "main.rs": "use rayon::prelude::*;

#[derive(Debug, Default, Clone)]
struct B {
    r: Vec<f64>,
    v: Vec<f64>,
    f: Vec<f64>,
    nb: Vec<usize>,
}

impl B {
    pub fn criterion(&self, other: &B) -> f64 {
        let dx = self.r[0] - other.r[0];
        let dy = self.r[1] - other.r[1];
        let dz = self.r[2] - other.r[2];

        dx * dx + dy * dy + dz * dz
    }
}

#[derive(Debug, Default, Clone)]
struct A {
    elems: Vec<B>,
    cutoff: f64,
}

impl A {
    pub fn get_nelems(&self) -> usize {
        self.elems.len()
    }

    // 1) Safe, no copies: use split_at_mut to get disjoint borrows.
    // 2) Modify both i and j when criterion holds (we only visit each pair once).
    pub fn build_lists_sequential(&mut self) {
        let n = self.elems.len();
        for b in &mut self.elems {
            b.nb.clear();
        }

        for i in 0..n {
            for j in (i + 1)..n {
                // Borrow elems[i] and elems[j] mutably and safely.
                let (left, right) = self.elems.split_at_mut(j);
                let bi = &mut left[i];
                let bj = &mut right[0];

                if bi.criterion(bj) < self.cutoff {
                    bi.nb.push(j);
                    bj.nb.push(i);
                }
            }
        }
    }

    // 3) Parallel version without unsafe pointers:
    //    compute neighbor lists in parallel into temporary vectors, then assign back.
    //    This avoids having to mutably touch two elements from different threads.
    pub fn build_lists_parallel(&mut self) {
        let n = self.elems.len();

        // Read-only snapshot for the parallel phase.
        // (No cloning of B or its contents; just shared borrows.)
        let elems: &[B] = &self.elems;
        let cutoff = self.cutoff;

        // For each i, compute nb[i] independently in parallel.
        let nbs: Vec<Vec<usize>> = (0..n)
            .into_par_iter()
            .map(|i| {
                let mut nb = Vec::new();
                for j in 0..n {
                    if i == j {
                        continue;
                    }
                    if elems[i].criterion(&elems[j]) < cutoff {
                        nb.push(j);
                    }
                }
                nb
            })
            .collect();

        // Single-threaded commit back into self.
        for (b, nb) in self.elems.iter_mut().zip(nbs) {
            b.nb = nb;
        }
    }
}

fn main() {
    // Tiny demo
    let mut a = A {
        cutoff: 1.5,
        elems: vec![
            B {
                r: vec![0.0, 0.0, 0.0],
                ..Default::default()
            },
            B {
                r: vec![1.0, 0.0, 0.0],
                ..Default::default()
            },
            B {
                r: vec![3.0, 0.0, 0.0],
                ..Default::default()
            },
        ],
    };

    a.build_lists_sequential();
    println!("Sequential nb: {:?}", a.elems.iter().map(|b| &b.nb).collect::<Vec<_>>());

    a.build_lists_parallel();
    println!("Parallel   nb: {:?}", a.elems.iter().map(|b| &b.nb).collect::<Vec<_>>());
}
