  "main.rs": "use rxrust::prelude::*;
use std::convert::Infallible;

type Obs = LocalBoxedObservableClone<'static, bool, Infallible>;

fn nand(name: &'static str, a: Obs, b: Obs) -> Obs {
    a.combine_latest(b, |a, b| (a, b))
        .distinct()
        .tap(move |(a, b)| print!("nand {name} ({a}, {b})"))
        .map(|(a, b)| !(a & b))
        .tap(|v| println!(" = {v}"))
        .box_it_clone()
}

fn flipflop(s: Obs, r: Obs) -> (Obs, Obs) {
    // These subjects represent the *feedback wires*.
    // Important: don't call `next()` on them re-entrantly from within the same
    // synchronous emission chain; schedule the feedback to happen later.
    let mut s2 = Local::behavior_subject::<bool, Infallible>(false);
    let mut r2 = Local::behavior_subject::<bool, Infallible>(false);

    let s2_obs = s2.clone().box_it_clone();
    let r2_obs = r2.clone().box_it_clone();

    let q1 = nand("s", s, s2_obs).box_it_clone();
    let q2 = nand("r", r, r2_obs).box_it_clone();

    // Break the synchronous recursion by deferring feedback using a local scheduler.
    // This avoids nested borrows inside BehaviorSubject (RefCell already borrowed).
    let sched = Local::scheduler();

    {
        let mut r2 = r2.clone();
        let sched = sched.clone();
        q1.clone().subscribe(move |v| {
            let mut r2 = r2.clone();
            sched.spawn(move || {
                r2.next(v);
            });
        });
    }

    {
        let mut s2 = s2.clone();
        let sched = sched.clone();
        q2.clone().subscribe(move |v| {
            let mut s2 = s2.clone();
            sched.spawn(move || {
                s2.next(v);
            });
        });
    }

    (q1, q2)
}

fn main() {
    let mut s = Local::behavior_subject::<bool, Infallible>(true);
    let mut r = Local::behavior_subject::<bool, Infallible>(true);

    let (q1, q2) = flipflop(s.clone().box_it_clone(), r.clone().box_it_clone());

    q1.combine_latest(q2, |q1, q2| (q1, q2))
        .subscribe(|(q1, q2)| println!("(q1={q1}, q2={q2})"));

    // Drive inputs
    s.next(false);
    s.next(true);

    r.next(false);
    r.next(true);

    // Give the scheduled feedback tasks time to run.
    // (In a real app you'd have an event loop; here we just flush the scheduler.)
    Local::scheduler().run();
}
"
}

