    thread,
    time::Duration,
};

use tracing::{info, warn, Level};
use tracing_subscriber::{
    filter,
    fmt,
    layer::SubscriberExt,
    reload,
    util::SubscriberInitExt,
    Registry,
};

fn main() {
    // File writer
    let file = OpenOptions::new()
        .append(true)
        .create(true)
        .open("logfile.log")
        .unwrap();

    // Console layer with a reloadable filter
    let console_layer = fmt::layer().compact().with_ansi(true);
    let (console_filter_layer, console_handle) = reload::Layer::new(
        console_layer.with_filter(filter::LevelFilter::from_level(Level::INFO)),
    );

    // File layer with a reloadable filter (independent from console)
    let file_layer = fmt::layer().with_ansi(false).with_writer(file);
    let (file_filter_layer, file_handle) = reload::Layer::new(
        file_layer.with_filter(filter::LevelFilter::from_level(Level::INFO)),
    );

    // IMPORTANT: set the global default only once.
    let subscriber = Registry::default().with(console_filter_layer).with(file_filter_layer);
    subscriber.init();

    // Emit logs periodically in a background thread.
    thread::spawn(|| loop {
        info!("info message");
        warn!("warn message");
        thread::sleep(Duration::from_millis(800));
    });

    // Simple interactive loop to change levels at runtime.
    // Commands:
    //   c <LEVEL>  - set console level (ERROR|WARN|INFO|DEBUG|TRACE|OFF)
    //   f <LEVEL>  - set file level
    //   q          - quit
    eprintln!(
        "Commands: `c <level>` (console), `f <level>` (file), `q`\nExample: `c ERROR` or `f TRACE`"
    );

    let stdin = io::stdin();
    loop {
        eprint!("> ");
        let _ = io::stderr().flush();

        let mut line = String::new();
        if stdin.read_line(&mut line).is_err() {
            continue;
        }
        let line = line.trim();
        if line.eq_ignore_ascii_case("q") {
            break;
        }

        let mut parts = line.split_whitespace();
        let target = parts.next();
        let level = parts.next();

        match (target, level) {
            (Some("c"), Some(lvl)) => {
                if let Some(f) = parse_level_filter(lvl) {
                    console_handle
                        .modify(|layer| {
                            *layer.filter_mut() = f;
                        })
                        .unwrap();
                    eprintln!("console level set to {f:?}");
                } else {
                    eprintln!("unknown level: {lvl}");
                }
            }
            (Some("f"), Some(lvl)) => {
                if let Some(f) = parse_level_filter(lvl) {
                    file_handle
                        .modify(|layer| {
                            *layer.filter_mut() = f;
                        })
                        .unwrap();
                    eprintln!("file level set to {f:?}");
                } else {
                    eprintln!("unknown level: {lvl}");
                }
            }
            _ => {
                eprintln!("Usage: `c <level>` or `f <level>` or `q`");
            }
        }
    }
}

fn parse_level_filter(s: &str) -> Option<filter::LevelFilter> {
    match s.to_ascii_uppercase().as_str() {
        "OFF" => Some(filter::LevelFilter::OFF),
        "ERROR" => Some(filter::LevelFilter::ERROR),
        "WARN" | "WARNING" => Some(filter::LevelFilter::WARN),
        "INFO" => Some(filter::LevelFilter::INFO),
        "DEBUG" => Some(filter::LevelFilter::DEBUG),
        "TRACE" => Some(filter::LevelFilter::TRACE),
        _ => None,
    }
}
"
}

