// -------------------- Drag Provider --------------------

#[derive(Clone, Copy, PartialEq, Eq, Debug)]
struct DragId(u32);

#[derive(Clone, Copy, Debug, Default)]
struct Pt {
    x: f64,
    y: f64,
}

#[derive(Clone, Copy, Debug)]
enum DragEvent {
    Start { id: DragId, pos: Pt },
    Move { id: DragId, pos: Pt },
    End { id: DragId },
}

/// A very small pub/sub style drag bus.
///
/// Key idea: children can register a callback. The provider calls those callbacks
/// on global pointer/mouse events.
#[derive(Clone)]
struct DragBus {
    inner: Signal<DragBusInner>,
}

struct DragBusInner {
    active: Option<DragId>,
    listeners: Vec<(DragId, Callback<DragEvent>)>,
}

impl DragBus {
    fn new() -> Self {
        Self {
            inner: Signal::new(DragBusInner {
                active: None,
                listeners: vec![],
            }),
        }
    }

    /// Register a listener for a particular id.
    ///
    /// Returned closure is an "unsubscribe" handle.
    fn subscribe(&self, id: DragId, cb: Callback<DragEvent>) -> impl FnOnce() {
        self.inner.write().listeners.push((id, cb));
        let inner = self.inner;
        move || {
            inner
                .write()
                .listeners
                .retain(|(existing, _)| *existing != id);
        }
    }

    fn set_active(&self, id: Option<DragId>) {
        self.inner.write().active = id;
    }

    fn active(&self) -> Option<DragId> {
        self.inner.read().active
    }

    fn emit(&self, evt: DragEvent) {
        // Copy out to avoid borrow issues if callbacks mutate state.
        let listeners = self.inner.read().listeners.clone();
        match evt {
            DragEvent::Start { id, .. } | DragEvent::Move { id, .. } => {
                for (lid, cb) in listeners {
                    if lid == id {
                        cb.call(evt);
                    }
                }
            }
            DragEvent::End { id } => {
                for (lid, cb) in listeners {
                    if lid == id {
                        cb.call(evt);
                    }
                }
            }
        }
    }
}

#[component]
fn DragProvider(children: Element) -> Element {
    let bus = use_context_provider(DragBus::new);

    // Attach global move/up listeners so dragging continues even outside SVG/point.
    // We use raw DOM events via `web_sys`.
    use_effect(move || {
        use web_sys::{window, MouseEvent};

        let win = window().expect("window");

        // mousemove handler
        let bus_move = bus.clone();
        let move_closure = Closure::<dyn FnMut(MouseEvent)>::new(move |e: MouseEvent| {
            if let Some(id) = bus_move.active() {
                let pos = Pt {
                    x: e.client_x() as f64,
                    y: e.client_y() as f64,
                };
                bus_move.emit(DragEvent::Move { id, pos });
            }
        });

        // mouseup handler
        let bus_up = bus.clone();
        let up_closure = Closure::<dyn FnMut(MouseEvent)>::new(move |_e: MouseEvent| {
            if let Some(id) = bus_up.active() {
                bus_up.emit(DragEvent::End { id });
                bus_up.set_active(None);
            }
        });

        win.add_event_listener_with_callback("mousemove", move_closure.as_ref().unchecked_ref())
            .expect("add mousemove listener");
        win.add_event_listener_with_callback("mouseup", up_closure.as_ref().unchecked_ref())
            .expect("add mouseup listener");

        // keep closures alive; cleanup on drop
        move || {
            let _ = win.remove_event_listener_with_callback(
                "mousemove",
                move_closure.as_ref().unchecked_ref(),
            );
            let _ = win.remove_event_listener_with_callback(
                "mouseup",
                up_closure.as_ref().unchecked_ref(),
            );
        }
    });

    rsx! {
        div {
            class: "wrap",
            {children}
        }
    }
}

// -------------------- Draggable Point --------------------

#[derive(Props, Clone, PartialEq)]
struct PointProps {
    id: u32,
    x: f64,
    y: f64,
    r: f64,
}

#[component]
fn Point(props: PointProps) -> Element {
    let bus = use_context::<DragBus>();

    // Position stored locally; only this component rerenders when it changes.
    let mut pos = use_signal(|| Pt { x: props.x, y: props.y });

    // Track if we're currently dragged (for styling).
    let mut dragging = use_signal(|| false);

    // Convert client coords to SVG coords.
    // We compute (client -> svg user units) using the svg element's bounding rect.
    // This is a simplified mapping that works for viewBox="0 0 W H" and no transforms.
    let to_svg_coords = |client: Pt| -> Pt {
        let doc = web_sys::window().unwrap().document().unwrap();
        let svg = doc
            .get_element_by_id("schema")
            .expect("svg#schema exists");
        let rect = svg.get_bounding_client_rect();

        // viewBox is 0..800 x 0..420 in this demo
        let w = rect.width();
        let h = rect.height();

        let x = (client.x - rect.left()) * (800.0 / w);
        let y = (client.y - rect.top()) * (420.0 / h);
        Pt { x, y }
    };

    // Subscribe this point to drag events.
    // This is the "custom event handler" hook-up: provider emits, point reacts.
    {
        let bus = bus.clone();
        let id = DragId(props.id);
        let mut pos = pos;
        let mut dragging = dragging;
        use_effect(move || {
            let unsub = bus.subscribe(
                id,
                Callback::new(move |evt: DragEvent| match evt {
                    DragEvent::Start { .. } => {
                        dragging.set(true);
                    }
                    DragEvent::Move { pos: client_pos, .. } => {
                        let p = to_svg_coords(client_pos);
                        pos.set(p);
                    }
                    DragEvent::End { .. } => {
                        dragging.set(false);
                    }
                }),
            );

            move || {
                unsub();
            }
        });
    }

    let class = if *dragging.read() {
        "point dragging"
    } else {
        "point"
    };

    rsx! {
        circle {
            class,
            cx: "{pos.read().x}",
            cy: "{pos.read().y}",
            r: "{props.r}",

            // On mousedown, mark this id active and emit Start.
            onmousedown: move |e| {
                // Prevent text selection / unwanted default behavior.
                e.prevent_default();
                e.stop_propagation();

                let id = DragId(props.id);
                bus.set_active(Some(id));
                bus.emit(DragEvent::Start {
                    id,
                    pos: Pt { x: e.client_coordinates().x as f64, y: e.client_coordinates().y as f64 }
                });
            }
        }
    }
}

