// - Run inside kitty terminal.
// - termion used only to get terminal pixel size.

fn main() -> io::Result<()> {
    let mut out = io::stdout().lock();

    // Best-effort pixel size; fallback if unavailable.
    let (w_px, h_px) = termion::terminal_size_pixels().unwrap_or((800, 600));
    let (width, height) = (w_px as usize, h_px as usize);

