    let file: File = tempfile()?;
    file.set_len(frame_bytes as u64)?;

    // Memory map the file so writing is just writing to memory.
    let mut mmap: MmapMut = unsafe { MmapOptions::new().len(frame_bytes).map_mut(&file)? };

    // We need a real path to pass to kitty. /proc/self/fd/<fd> works on Linux.
    // kitty will open/read that path.
    let fd = file.as_raw_fd();
    let path = format!("/proc/self/fd/{fd}");

    // Clear screen, hide cursor.
    write!(out, "\x1b[2J\x1b[H\x1b[?25l")?;
    out.flush()?;

    // Target ~60 fps.
    let frame_dt = Duration::from_nanos(1_000_000_000u64 / 60);
    let mut next_frame = Instant::now();

    // Use a fixed image id so subsequent frames replace the same image.
    let image_id = 1;

    let mut t: f32 = 0.0;
    loop {
        // Throttle.
        let now = Instant::now();
        if now < next_frame {
            thread::sleep(next_frame - now);
        }
        next_frame += frame_dt;

