use rustyline::error::ReadlineError;
use rustyline::highlight::Highlighter;
use rustyline::hint::Hinter;
use rustyline::validate::Validator;
use rustyline::{Context, DefaultEditor, Helper, Result};

// A Helper is where rustyline looks for completion/hints/etc.
// You register it with Editor::set_helper(Some(helper)).
