    filename: FilenameCompleter,
}

impl MyHelper {
    fn new() -> Self {
        Self {
            filename: FilenameCompleter::new(),
        }
    }
}

impl Helper for MyHelper {}

impl Hinter for MyHelper {
    type Hint = String;
}

impl Highlighter for MyHelper {}
impl Validator for MyHelper {}

impl Completer for MyHelper {
    type Candidate = Pair;

    fn complete(
        &self,
        line: &str,
        pos: usize,
        ctx: &Context<'_>,
    ) -> std::result::Result<(usize, Vec<Pair>), ReadlineError> {
        // Minimal “shell-ish” behavior:
        // - If we're completing the first word: suggest builtins.
        // - Otherwise: fall back to filename completion.
        let before_cursor = &line[..pos];
        let first_word = before_cursor.split_whitespace().next().unwrap_or("");
        let completing_first_word = before_cursor.trim_start() == first_word
            && !before_cursor.contains(char::is_whitespace);

        if completing_first_word {
            let builtins = ["exit", "echo", "cd", "pwd", "type"];

            // Find the start of the current token (simple: last whitespace)
            let start = before_cursor
                .rfind(char::is_whitespace)
                .map(|i| i + 1)
                .unwrap_or(0);
            let needle = &before_cursor[start..];

            let matches: Vec<Pair> = builtins
                .iter()
                .filter(|b| b.starts_with(needle))
                .map(|b| Pair {
                    display: b.to_string(),
                    replacement: b.to_string(),
                })
                .collect();

            Ok((start, matches))
        } else {
            // Delegate to the built-in filename completer.
            self.filename.complete(line, pos, ctx)
        }
    }
}

fn main() -> Result<()> {
    let mut rl = DefaultEditor::new()?;

    // IMPORTANT: the type parameter of DefaultEditor is inferred from set_helper.
    // Without setting a helper, DefaultEditor uses () which does nothing.
    rl.set_helper(Some(MyHelper::new()));

    loop {
        match rl.readline(">> ") {
            Ok(line) => {
                rl.add_history_entry(line.as_str())?;
                println!("Line: {line}");
                if line.trim() == "exit" {
                    break;
                }
            }
            Err(ReadlineError::Interrupted) => break,
            Err(ReadlineError::Eof) => break,
            Err(err) => {
                eprintln!("Error: {err:?}");
                break;
            }
        }
    }

    Ok(())
}
