            }
        }

        let current_index: Vec<usize> = self
            .current_index_option
            .iter()
            .map(|x| x.unwrap())
            .collect();
        let current_value: &'a T = self.array.get(&current_index);
        Some((current_index, current_value))
    }
}

// ---------- Mutable iterator: FIXED using raw pointer + unsafe ----------
//
// Why unsafe is needed:
// Iterator::Item cannot express "a mutable reference tied to &mut self for this call".
// The trait requires an associated type, not a per-call lifetime.
// If you write Item = &'a mut T, that would allow holding TWO &'a mut T from two next() calls,
// which would violate Rust aliasing rules.
//
// Standard library solves this for slices with special internal machinery.
// For your custom structure, the common pattern is:
// - store a raw pointer to the buffer
// - compute indices and create &mut T with unsafe each step
// - ensure by construction you never yield the same element twice
//
#[derive(Debug)]
pub struct ArrayIteratorFromDynMut<'a, T> {
    // raw pointer into the backing store; we do NOT keep &mut Array<T> here,
    // because next() must be able to yield &mut T while still having &mut self.
    ptr: *mut T,
    len: usize,
    dims: Vec<usize>,

    selection_iterators: Vec<Box<dyn ArrayViewIterator>>,
    current_iterators: Vec<Box<dyn ArrayViewIterator>>,
    current_index_option: Vec<Option<usize>>,

    _marker: std::marker::PhantomData<&'a mut T>,
}

impl<'a, T> ArrayIteratorFromDynMut<'a, T> {
    pub fn new(array: &'a mut Array<T>, iters: Vec<Box<dyn ArrayViewIterator>>) -> Self {
        let mut current_iterators: Vec<Box<dyn ArrayViewIterator>> =
            iters.iter().map(|it| dyn_clone::clone_box(&**it)).collect();
        let mut current_index_option = vec![None; iters.len()];
        if !iters.is_empty() {
            current_index_option[0] = current_iterators[0].next();
        }

        Self {
            ptr: array.as_mut_ptr(),
            len: array.len(),
            dims: array.dims.clone(),
            selection_iterators: iters,
            current_iterators,
            current_index_option,
            _marker: std::marker::PhantomData,
        }
    }

    fn linear_index(&self, idx: &[usize]) -> usize {
        assert_eq!(idx.len(), self.dims.len());
        let mut stride = 1;
        let mut lin = 0;
        for (i, &dim_i) in self.dims.iter().enumerate().rev() {
            let v = idx[i];
            assert!(v < dim_i);
            lin += v * stride;
            stride *= dim_i;
        }
        lin
    }
}

impl<'a, T> Iterator for ArrayIteratorFromDynMut<'a, T> {
    // Note: This is still &'a mut T, but we uphold the aliasing rule by construction
    // (don’t yield the same element twice). Users must also not keep multiple yielded
    // &mut T alive simultaneously if indices could repeat.
    type Item = (Vec<usize>, &'a mut T);

    fn next(&mut self) -> Option<Self::Item> {
        if self.selection_iterators.is_empty() {
            return None;
        }

        self.current_index_option[0] = self.current_iterators[0].next();

        for i in 0..self.selection_iterators.len() {
            if self.current_index_option[i].is_none() {
                if i == self.selection_iterators.len() - 1 {
                    return None;
                }
                self.current_iterators[i] = dyn_clone::clone_box(&*self.selection_iterators[i]);
                self.current_index_option[i] = self.current_iterators[i].next();
                if i < self.selection_iterators.len() - 1 {
                    self.current_index_option[i + 1] = self.current_iterators[i + 1].next();
                }
            } else {
                break;
            }
        }

        let current_index: Vec<usize> = self
            .current_index_option
            .iter()
            .map(|x| x.unwrap())
            .collect();
        let lin = self.linear_index(&current_index);
        assert!(lin < self.len);

        // SAFETY:
        // - ptr is valid for len elements for the lifetime 'a (comes from &mut Array<T>).
        // - We create one &mut T per iteration step.
        // - Correctness requires the iterator never yields the same lin twice.
        let current_value: &'a mut T = unsafe { &mut *self.ptr.add(lin) };
        Some((current_index, current_value))
    }
}

fn main() {
    let mut a = Array::from_vec(vec![2, 3], (0..6).collect::<Vec<i32>>());

    // iterate immutably
    let iters1: Vec<Box<dyn ArrayViewIterator>> = vec![Box::new(0..2), Box::new(0..3)];
    let it = ArrayIteratorFromDyn::new(&a, iters1);
    for (idx, v) in it {
        println!("immutable idx={idx:?} v={v}");
    }

    // iterate mutably: add 10 to each element
    let iters2: Vec<Box<dyn ArrayViewIterator>> = vec![Box::new(0..2), Box::new(0..3)];
    let it_mut = ArrayIteratorFromDynMut::new(&mut a, iters2);
    for (_idx, v) in it_mut {
        *v += 10;
    }

    // check result
    let iters3: Vec<Box<dyn ArrayViewIterator>> = vec![Box::new(0..2), Box::new(0..3)];
    let it2 = ArrayIteratorFromDyn::new(&a, iters3);
    for (idx, v) in it2 {
        println!("after mut idx={idx:?} v={v}");
    }
}
"
}

