  "main.rs": "use anyhow::Result;
use bevy::{
    asset::{io::Reader, AssetLoader, LoadContext},
    prelude::*,
    reflect::TypePath,
};

/// An "index" asset that represents a container file.
/// It does NOT eagerly decode individual textures; it just stores metadata
/// (names + byte ranges) and keeps the raw bytes around so we can resolve
/// entries on demand.
#[derive(Asset, TypePath, Debug, Clone)]
pub struct WadIndex {
    pub entries: Vec<WadEntry>,
    pub bytes: Vec<u8>,
}

#[derive(Debug, Clone)]
pub struct WadEntry {
    pub name: String,
    pub offset: usize,
    pub len: usize,
}

/// A "sub-asset" representing one extracted entry.
/// In a real implementation this could be an Image, AudioSource, etc.
#[derive(Asset, TypePath, Debug, Clone)]
pub struct WadChunk {
    pub name: String,
    pub data: Vec<u8>,
}

/// Loads a whole container file, but only builds an index (plus keeps raw bytes).
/// This is the typical pattern for "lazy" access with Bevy: one root asset that
/// can then be queried to load specific sub-assets on demand.
#[derive(Default)]
pub struct WadIndexLoader;

impl AssetLoader for WadIndexLoader {
    type Asset = WadIndex;
    type Settings = ();
    type Error = anyhow::Error;

    fn extensions(&self) -> &[&str] {
        &["wadlike"]
    }

    async fn load(
        &self,
        reader: &mut dyn Reader,
        _settings: &Self::Settings,
        _load_context: &mut LoadContext<'_>,
    ) -> std::result::Result<Self::Asset, Self::Error> {
        // Note: Bevy's AssetLoader API provides a Reader and you can stream.
        // Here we read into memory for simplicity.
        let mut bytes = Vec::new();
        reader.read_to_end(&mut bytes).await?;

        // Our demo container format is:
        // [u32 count]
        // repeated count times:
        //   [u8 name_len][name bytes][u32 data_len][data bytes]
        let mut cursor = 0usize;
        let count = read_u32(&bytes, &mut cursor)? as usize;
        let mut entries = Vec::with_capacity(count);

        for _ in 0..count {
            let name_len = read_u8(&bytes, &mut cursor)? as usize;
            let name = read_string(&bytes, &mut cursor, name_len)?;
            let data_len = read_u32(&bytes, &mut cursor)? as usize;
            let offset = cursor;
            cursor = cursor
                .checked_add(data_len)
                .ok_or_else(|| anyhow::anyhow!("overflow"))?;
            if cursor > bytes.len() {
                anyhow::bail!("truncated container");
            }
            entries.push(WadEntry {
                name,
                offset,
                len: data_len,
            });
        }

        Ok(WadIndex { entries, bytes })
    }
}

/// A second loader that can load a single chunk out of the container.
/// The important bit: you can request this asset by a "virtual path" like
/// `my_container.wadlike#chunk_name`.
#[derive(Default)]
pub struct WadChunkLoader;

impl AssetLoader for WadChunkLoader {
    type Asset = WadChunk;
    type Settings = ();
    type Error = anyhow::Error;

    fn extensions(&self) -> &[&str] {
        // We implement no "real" extension; we just rely on the full path string.
        // Bevy picks the loader by extension, so we give a fake extension that we
        // will use in the path, e.g. `something.wadchunk`.
        &["wadchunk"]
    }

    async fn load(
        &self,
        reader: &mut dyn Reader,
        _settings: &Self::Settings,
        load_context: &mut LoadContext<'_>,
    ) -> std::result::Result<Self::Asset, Self::Error> {
        // This loader expects the file bytes to be a serialized request that tells it
        // which container and which entry to read. In a real implementation you would
        // implement a custom AssetSource/AssetReader to allow random access into the
        // container without copying.
        //
        // For a self-contained demo without custom IO, we encode:
        // [u8 container_path_len][container_path bytes][u8 entry_name_len][entry_name bytes]
        let mut bytes = Vec::new();
        reader.read_to_end(&mut bytes).await?;
        let mut cursor = 0usize;
        let cpl = read_u8(&bytes, &mut cursor)? as usize;
        let container_path = read_string(&bytes, &mut cursor, cpl)?;
        let enl = read_u8(&bytes, &mut cursor)? as usize;
        let entry_name = read_string(&bytes, &mut cursor, enl)?;

        // Load the container index as a dependency.
        let index_handle: Handle<WadIndex> = load_context.load(container_path);

        // Defer actual extraction until after dependencies are available by using a
        // "post load" step. Here we do it synchronously by accessing the world assets
        // later in a system (see `resolve_chunks_system`).
        // We return an empty chunk for now and fill it later.
        Ok(WadChunk {
            name: format!("{} (pending)", entry_name),
            data: Vec::new(),
        })
    }
}

/// Resource tracking a request to resolve a WadChunk after its index is ready.
#[derive(Resource, Default)]
struct PendingChunkRequests {
    // (chunk_handle_id, container_handle, entry_name)
    items: Vec<(Handle<WadChunk>, Handle<WadIndex>, String)>,
}

fn main() {
    App::new()
        .add_plugins(DefaultPlugins.set(AssetPlugin {
            // We use Bevy's default `assets/` directory.
            // You can also set `file_path` here.
            ..default()
        }))
        .init_resource::<PendingChunkRequests>()
        .init_asset::<WadIndex>()
        .init_asset::<WadChunk>()
        .register_asset_loader(WadIndexLoader::default())
        .register_asset_loader(WadChunkLoader::default())
        .add_systems(Startup, setup)
        .add_systems(Update, (queue_demo_requests_system, resolve_chunks_system))
        .run();
}

fn setup(mut commands: Commands) {
    commands.spawn(Camera2dBundle::default());
}

/// Creates a demo container file in memory via the AssetServer by writing it into
/// `assets/` at runtime is not supported; instead we demonstrate the *pattern*:
/// 1) Load container index once
/// 2) Later, request individual entries
///
/// To make `cargo run` work without external files, we use `include_bytes!`-style
/// bytes by registering them into the AssetServer via `AssetServer::add_source` is
/// not available in Bevy 0.14 stable without custom AssetSource plumbing.
///
/// So: this system just prints guidance and exits.
fn queue_demo_requests_system(
    asset_server: Res<AssetServer>,
    mut once: Local<bool>,
) {
    if *once {
        return;
    }
    *once = true;

    // IMPORTANT NOTE:
    // This demo focuses on the *architecture* for lazy access.
    // To actually run it, create an `assets/demo.wadlike` file.
    // Format is described in `WadIndexLoader`.

    info!(
        "Create assets/demo.wadlike and re-run. Then this demo will load it and lazily extract entries.\n\
Format: [u32 count] then for each: [u8 name_len][name bytes][u32 data_len][data bytes]."
    );

    // If the file exists, we proceed.
    let index: Handle<WadIndex> = asset_server.load("demo.wadlike");

    info!("Requested container index: {:?}", index);

    // Example of requesting an extracted entry: we do it by loading a synthetic `.wadchunk`
    // asset that encodes (container_path, entry_name).
    // In a real project you'd instead implement a custom AssetReader that can open
    // `demo.wadlike#entry_name` and read only that range.
    let chunk0: Handle<WadChunk> = asset_server.load("demo_entry0.wadchunk");
    let chunk1: Handle<WadChunk> = asset_server.load("demo_entry1.wadchunk");

    info!("Requested chunks: {:?}, {:?}", chunk0, chunk1);

    // Note: those `.wadchunk` files also need to exist in assets/ for this simplified demo.
    // We print where Bevy expects assets to live.
    info!(
        "Bevy will look for files under the asset root (by default ./assets). AssetServer root is typically relative." 
    );
}

/// In a real implementation, `WadChunkLoader` would parse its path and perform
/// range reads from the container via a custom AssetReader.
///
/// Here we show how you *would* resolve a chunk lazily once the index is ready.
fn resolve_chunks_system(
    mut chunks: ResMut<Assets<WadChunk>>,
    indices: Res<Assets<WadIndex>>,
) {
    // In this self-contained version we can't enqueue properly without real files,
    // but we keep the system to show the pattern.
    for (_id, chunk) in chunks.iter_mut() {
        if chunk.data.is_empty() {
            // No-op; in a real setup you'd fill from index bytes.
            // Example code (pseudo):
            // if let Some(index) = indices.get(&container_handle) {
            //    let entry = index.entries.iter().find(|e| e.name==entry_name).unwrap();
            //    chunk.data = index.bytes[entry.offset..entry.offset+entry.len].to_vec();
            //    chunk.name = entry.name.clone();
            // }
            let _ = &indices;
        }
    }
}

fn read_u8(bytes: &[u8], cursor: &mut usize) -> Result<u8> {
    if *cursor + 1 > bytes.len() {
        anyhow::bail!("unexpected eof");
    }
    let v = bytes[*cursor];
    *cursor += 1;
    Ok(v)
}

fn read_u32(bytes: &[u8], cursor: &mut usize) -> Result<u32> {
    if *cursor + 4 > bytes.len() {
        anyhow::bail!("unexpected eof");
    }
    let v = u32::from_le_bytes(bytes[*cursor..*cursor + 4].try_into().unwrap());
    *cursor += 4;
    Ok(v)
}

fn read_string(bytes: &[u8], cursor: &mut usize, len: usize) -> Result<String> {
    if *cursor + len > bytes.len() {
        anyhow::bail!("unexpected eof");
    }
    let s = std::str::from_utf8(&bytes[*cursor..*cursor + len])?.to_string();
    *cursor += len;
    Ok(s)
}
