            other => {
                return Err(de::Error::custom(format!(
                    "invalid type for path_list: expected array or $ref object, got {other}")));
            }
        };

        Ok(A { path_list: paths })
    }
}

fn resolve_ref_to_path_list(ref_str: &str) -> Result<Vec<PathBuf>, String> {
    // Minimal resolver for refs like: "./a.json#/p_list"
    let (file_part, pointer_part) = ref_str
        .split_once('#')
        .ok_or_else(|| "ref must contain '#' (e.g. ./a.json#/p_list)".to_string())?;

    // Interpret file path relative to current working directory.
    let file_path = Path::new(file_part);

    let json_text = fs::read_to_string(file_path)
        .map_err(|e| format!("reading {}: {e}", file_path.display()))?;

    let doc: Value = serde_json::from_str(&json_text)
        .map_err(|e| format!("parsing {}: {e}", file_path.display()))?;

