}

fn resolve_json_pointer<'a>(root: &'a Value, pointer_with_slash: &str) -> Option<&'a Value> {
    // Expects pointer like "/p_list" (as in "#/p_list").
    // Implements the essential JSON Pointer rules, including ~0 and ~1 unescaping.
    if pointer_with_slash.is_empty() {
        return Some(root);
    }
    if !pointer_with_slash.starts_with('/') {
        return None;
    }

    let mut cur = root;
    for raw_token in pointer_with_slash.split('/').skip(1) {
        let token = raw_token.replace("~1", "/").replace("~0", "~");
        match cur {
            Value::Object(map) => {
                cur = map.get(&token)?;
            }
            Value::Array(arr) => {
                let idx: usize = token.parse().ok()?;
                cur = arr.get(idx)?;
            }
            _ => return None,
        }
    }
    Some(cur)
}

