    while let Some(p) = cur {
        let seg = p.segment()?;
        let name_ref = seg.name_ref()?;
        segs.push(name_ref.text().to_string());
        cur = p.qualifier();
    }

    segs.reverse();

    // We only rewrite paths whose first segment is exactly `vexide`.
    if segs.first().map(|s| s.as_str()) != Some("vexide") {
        return None;
    }

    // Remove a `devices` segment immediately after `vexide`.
    if segs.get(1).map(|s| s.as_str()) != Some("devices") {
        return None;
    }

    segs.remove(1);
    Some(segs.join("::"))
}
