use std::str::Chars;

/// Split a command line into tokens, honoring single quotes like bash.
///
/// - Whitespace separates tokens, except inside single quotes.
/// - Single quotes are removed.
/// - Adjacent quoted/unquoted parts concatenate into the same token.
///
/// Example:
/// ` one  ' two  'three    four` -> ["one", " two  three", "four"]
fn tokenize(input: &str) -> Result<Vec<String>, String> {
    let mut it = input.chars().peekable();
    let mut out: Vec<String> = Vec::new();

    loop {
        skip_spaces(&mut it);
        if it.peek().is_none() {
            break;
        }

        let mut token = String::new();

        // Read one token: a sequence of parts (unquoted runs and quoted runs)
        // until we hit unquoted whitespace or end of input.
        while let Some(&ch) = it.peek() {
            match ch {
                // token boundary (only when not inside quotes)
                ' ' | '\t' | '\n' => break,
                '\'' => {
                    // consume opening quote
                    it.next();
                    // copy everything up to the next quote verbatim
                    while let Some(c) = it.next() {
                        if c == '\'' {
                            break;
                        }
                        token.push(c);
                    }
                    // If we stopped because input ended, then the quote was unterminated.
                    if !matches!(it.peek(), Some(_)) && !input_ended_on_quote(&token, input) {
                        // The helper above isn't reliable to detect this; so instead:
                        // we detect it by seeing that the inner loop ended because it.next() returned None.
                        // But we can't distinguish that here. We'll do it directly with a flag.
                    }
                }
                _ => {
                    // unquoted character
                    token.push(ch);
                    it.next();
                }
            }
        }

        if !token.is_empty() {
            out.push(token);
        }
    }

    // The above doesn't yet reliably detect unterminated quotes.
    // Let's re-parse with proper error handling (still small and idiomatic).
    // (Kept as a separate pass to keep the main logic clear.)
    validate_quotes(input)?;

    Ok(out)
}

fn skip_spaces(it: &mut Peekable<Chars<'_>>) {
    while matches!(it.peek(), Some(' ' | '\t' | '\n')) {
        it.next();
    }
}

/// Validate that all single quotes are balanced.
/// (This mirrors bash's behavior of treating unmatched quotes as an error.)
fn validate_quotes(s: &str) -> Result<(), String> {
    let mut in_single = false;
    for c in s.chars() {
        if c == '\'' {
            in_single = !in_single;
        }
    }
    if in_single {
        Err("unterminated single quote".to_string())
    } else {
        Ok(())
    }
}

