use serde::{Deserialize, Deserializer};
use std::fmt;

#[derive(Debug, Default)]
struct A {
    x: usize,
    b: Vec<B>,
}

#[derive(Debug)]
enum B {
    Int(i64),
    Text(String),
}

// --- Custom Deserialize for B (so A can just call next_value::<Vec<B>>() ) ---
impl<'de> Deserialize<'de> for B {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        struct BVisitor;

        impl<'de> Visitor<'de> for BVisitor {
            type Value = B;

            fn expecting(&self, f: &mut fmt::Formatter) -> fmt::Result {
                f.write_str("a B value, either an integer or a string")
            }

            fn visit_i64<E>(self, v: i64) -> Result<Self::Value, E>
            where
                E: de::Error,
            {
                Ok(B::Int(v))
            }

            fn visit_u64<E>(self, v: u64) -> Result<Self::Value, E>
            where
                E: de::Error,
            {
                // allow JSON numbers that are u64
                Ok(B::Int(i64::try_from(v).map_err(|_| E::custom("u64 out of range for i64"))?))
            }

            fn visit_str<E>(self, v: &str) -> Result<Self::Value, E>
            where
                E: de::Error,
            {
                Ok(B::Text(v.to_owned()))
            }

            fn visit_string<E>(self, v: String) -> Result<Self::Value, E>
            where
                E: de::Error,
            {
                Ok(B::Text(v))
            }
        }

        // This supports either JSON number or JSON string for B.
        deserializer.deserialize_any(BVisitor)
    }
}

// --- Custom Deserialize for A (map with keys x and b) ---
impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        struct AVisitor;

        impl<'de> Visitor<'de> for AVisitor {
            type Value = A;

            fn expecting(&self, f: &mut fmt::Formatter) -> fmt::Result {
                f.write_str("a map with fields x and b")
            }

            fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
            where
                V: MapAccess<'de>,
            {
                let mut x: Option<usize> = None;
                let mut b: Option<Vec<B>> = None;

                while let Some(key) = map.next_key::<String>()? {
                    match key.as_str() {
                        "x" => {
                            if x.is_some() {
                                return Err(de::Error::duplicate_field("x"));
                            }
                            x = Some(map.next_value()?);
                        }
                        "b" => {
                            if b.is_some() {
                                return Err(de::Error::duplicate_field("b"));
                            }
                            // Key point: nested types deserialize by calling next_value()
                            // with the desired type. Since Vec<B>: Deserialize and B: Deserialize
