    io,
    path::{Path, PathBuf},
};

#[derive(Debug, Serialize, Deserialize, Clone)]
struct TodoItem {
    text: String,
    done: bool,
}

fn load_or_init(path: &Path) -> io::Result<Vec<TodoItem>> {
    match fs::read_to_string(path) {
        Ok(s) => {
            // If file exists but is empty/whitespace, treat it as empty list.
            if s.trim().is_empty() {
                return Ok(Vec::new());
            }

            // If JSON parsing fails, surface as an io::Error for simplicity.
            let v: Vec<TodoItem> = serde_json::from_str(&s)
                .map_err(|e| io::Error::new(io::ErrorKind::InvalidData, e))?;
            Ok(v)
        }
        Err(e) if e.kind() == io::ErrorKind::NotFound => Ok(Vec::new()),
        Err(e) => Err(e),
    }
}

fn save_atomic(path: &Path, todos: &[TodoItem]) -> io::Result<()> {
    let tmp_path: PathBuf = path.with_extension("json.tmp");
    let json = serde_json::to_string_pretty(todos)
        .map_err(|e| io::Error::new(io::ErrorKind::Other, e))?;

    // Write to a temp file then rename for safer updates.
    fs::write(&tmp_path, json)?;
    fs::rename(&tmp_path, path)?;
    Ok(())
}

fn append_todo(path: &Path, item: TodoItem) -> io::Result<()> {
    let mut todos = load_or_init(path)?;
    todos.push(item);
    save_atomic(path, &todos)
}

