    let todos = load_or_init(path)?;
    println!("Loaded {} todo item(s):", todos.len());
    for (i, t) in todos.iter().enumerate() {
        println!("{}. [{}] {}", i + 1, if t.done { "x" } else { " " }, t.text);
    }

    Ok(())
}
"
}
