  "main.rs": "//! Demonstrates a macro pattern that *forces* calling an inherent method
//! (or fails to compile if it doesn't exist) and avoids accidental recursion
//! into the trait method.

trait Foo {
    fn go(&self);
}

// This is the key: use UFCS with an inherent-method-qualified receiver type.
//
// `ConcreteFoo::go(self)` can still resolve to the trait method if the inherent
// method is missing, because method-call syntax participates in trait lookup.
//
// But `ConcreteFoo::go(&*self)` in *path* form forces the compiler to look for
// an inherent associated function named `go` on `ConcreteFoo` with the matching
// signature. If it doesn't exist, you get a hard compile error.
macro_rules! derive_foo_for {
    ($ty:ty) => {
        impl Foo for $ty {
            fn go(&self) {
                // Force inherent method resolution; no trait lookup here.
                <$ty>::go(&*self)
            }
        }
    };
}

struct ConcreteFoo;

impl ConcreteFoo {
    pub const fn go(&self) {
        // actual implementation
