{
  "Cargo.toml": "[package]
name = "sync_async_handler_demo"
version = "0.1.0"
edition = "2021"

[dependencies]
futures = "0.3"

",
  "main.rs": "use futures::future::BoxFuture;
use std::future::Future;
use std::sync::Arc;

// Minimal structs for illustration
#[derive(Debug)]
pub struct Request;
#[derive(Debug)]
pub struct Response(&'static str);

// Unified stored type: (&Request) -> BoxFuture<Response>
type HandlerFn =
    dyn for<'a> Fn(&'a Request) -> BoxFuture<'a, Response> + Send + Sync + 'static;

#[derive(Clone)]
pub struct Handler(Arc<HandlerFn>);

impl Handler {
    pub fn call<'a>(&self, req: &'a Request) -> BoxFuture<'a, Response> {
        (self.0)(req)
    }
}

// Key idea:
// Use two *constructor functions* instead of overlapping `From` impls.
// This avoids the HRTB/`impl Future` mismatch that happens for `async fn`.
impl Handler {
    /// Accepts an async handler: `for<'a> Fn(&'a Request) -> Fut`.
    ///
    /// Note: `async fn foo(req: &Request) -> Response` desugars to
    /// `for<'a> fn(&'a Request) -> impl Future<Output=Response> + 'a`, which
    /// matches this HRTB.
    pub fn from_async<F, Fut>(f: F) -> Self
    where
        F: for<'a> Fn(&'a Request) -> Fut + Send + Sync + 'static,
        Fut: Future<Output = Response> + Send + 'static,
    {
        Handler(Arc::new(move |req| {
            // We need a concrete future type to box. The easiest way is to
            // create an `async` block that awaits the user's future.
            Box::pin(async move { f(req).await })
        }))
    }

    /// Accepts a sync handler: `for<'a> Fn(&'a Request) -> Response`.
    pub fn from_sync<F>(f: F) -> Self
    where
        F: for<'a> Fn(&'a Request) -> Response + Send + Sync + 'static,
    {
        Handler(Arc::new(move |req| Box::pin(async move { f(req) })))
    }
}

pub struct Server {
    routes: Vec<(&'static str, Handler)>,
}

impl Server {
    pub fn new() -> Self {
        Self { routes: vec![] }
    }

    // This is the closest ergonomic API you can provide today without nightly
    // features/specialization: offer two methods.
    pub fn add_route_sync<F>(&mut self, path: &'static str, f: F)
    where
        F: for<'a> Fn(&'a Request) -> Response + Send + Sync + 'static,
    {
        self.routes.push((path, Handler::from_sync(f)));
    }

    pub fn add_route_async<F, Fut>(&mut self, path: &'static str, f: F)
    where
        F: for<'a> Fn(&'a Request) -> Fut + Send + Sync + 'static,
        Fut: Future<Output = Response> + Send + 'static,
    {
        self.routes.push((path, Handler::from_async(f)));
    }

    pub async fn handle(&self, path: &str, req: &Request) -> Option<Response> {
        let (_, h) = self.routes.iter().find(|(p, _)| *p == path)?;
        Some(h.call(req).await)
    }
}

fn sync_handler(_req: &Request) -> Response {
    Response("sync")
}

async fn async_handler(_req: &Request) -> Response {
    Response("async")
}

fn main() {
    // Demonstrate usage
    let mut server = Server::new();

    // These are ergonomic and compile on stable.
    server.add_route_sync("/sync", sync_handler);
    server.add_route_async("/async", async_handler);

    futures::executor::block_on(async {
        let req = Request;
        let r1 = server.handle("/sync", &req).await.unwrap();
        let r2 = server.handle("/async", &req).await.unwrap();
        println!("/sync -> {:?}", r1);
        println!("/async -> {:?}", r2);
    });
}
"
}

