  "main.rs": "use std::{borrow::Cow, collections::HashMap, marker::PhantomData};

/// Simulate an external crate trait.
///
/// The important bit: `group` and `kind` return `Cow<'a, str>` that may borrow
/// from the provided `dynamic_type`.
trait Resource {
    type DynamicType: Default;

    fn group<'a>(dt: &'a Self::DynamicType) -> Cow<'a, str>;
    fn kind<'a>(dt: &'a Self::DynamicType) -> Cow<'a, str>;

    fn meta(&self) -> Meta;
}

#[derive(Clone, Debug)]
struct Meta {
    name: Option<String>,
}

/// A sample dynamic type that owns the backing strings.
#[derive(Default, Debug, Clone)]
struct MyDynamicType {
    group: String,
    kind: String,
}

#[derive(Debug, Clone)]
struct MyResource {
    meta: Meta,
    dt: MyDynamicType,
}

impl MyResource {
    fn new(name: &str, group: &str, kind: &str) -> Self {
        Self {
            meta: Meta {
                name: Some(name.to_string()),
            },
            dt: MyDynamicType {
                group: group.to_string(),
                kind: kind.to_string(),
            },
        }
    }
}

impl Resource for MyResource {
    type DynamicType = MyDynamicType;

    fn group<'a>(dt: &'a Self::DynamicType) -> Cow<'a, str> {
        // Borrow from `dt`
        Cow::Borrowed(dt.group.as_str())
    }

    fn kind<'a>(dt: &'a Self::DynamicType) -> Cow<'a, str> {
        // Borrow from `dt`
        Cow::Borrowed(dt.kind.as_str())
    }

    fn meta(&self) -> Meta {
        self.meta.clone()
    }
}

/// Key type.
///
/// Fix: store owned `String` for `group`/`kind` (or otherwise ensure the borrowed
/// data outlives `Self`). You cannot store a `Cow` that borrows from `dynamic_type`
/// inside the same struct without self-referential trickery.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct ResourceRef<R: Resource>
where
    R::DynamicType: Default,
{
    _type: PhantomData<R>,
    dynamic_type: R::DynamicType,
    group: Option<String>,
    kind: String,
    name: String,
}

impl<R: Resource> ResourceRef<R>
where
    R::DynamicType: Default,
{
    pub fn new(resource: R) -> Self {
        let name = resource
            .meta()
            .name
            .as_deref()
            .expect("Resource must have a name")
            .to_string();
        Self::new_named(name)
    }

    pub fn new_named(name: impl Into<String>) -> Self {
        let dynamic_type = R::DynamicType::default();

        // `group` and `kind` may borrow from `dynamic_type`, so we must not store
        // them as borrowing Cows. Convert to owned.
        let group_cow = R::group(&dynamic_type);
        let group = if group_cow.is_empty() {
            None
        } else {
            Some(group_cow.into_owned())
        };

        let kind = R::kind(&dynamic_type).into_owned();

        Self {
            _type: PhantomData,
            dynamic_type,
            group,
            kind,
            name: name.into(),
        }
    }

    pub fn group(&self) -> Option<&str> {
        self.group.as_deref()
    }

    pub fn kind(&self) -> &str {
        &self.kind
