  "main.rs": "use anyhow::Result;
use crossbeam_channel::{select, unbounded};
use expectrl::{spawn, session::Session};
use std::io::{Read, Write};
use std::thread;
use std::time::Duration;

/// Demonstrates a safe full-duplex pattern with expectrl:
/// - One thread is the *only owner* of the expectrl Session (no Arc<Mutex<Session>>).
/// - UI/input thread(s) send keystrokes via a channel to the PTY thread.
/// - PTY thread continuously:
///   - drains pending writes from the channel
///   - reads output from the PTY using a short read timeout so it never blocks forever
///
/// Why this fixes the freeze:
/// - No mutex is held across a blocking read.
/// - Reads are bounded by a timeout, so the PTY thread regularly returns to process writes.
///
/// Run:
///   cargo run
/// Then type into the terminal. It will be forwarded to an interactive child shell.
fn main() -> Result<()> {
    // Spawn an interactive program. You can replace this with your agent (codex/gemini).
    // Keeping it simple: /bin/bash -i behaves like a typical interactive TTY app.
    let mut session = spawn("/bin/bash -i")?;

    // IMPORTANT: avoid blocking forever on read so we can interleave writes.
    // expectrl exposes a read timeout on the underlying session.
    // A small timeout keeps latency low while still being efficient.
    session.set_read_timeout(Some(Duration::from_millis(20)));

    // Channel for input -> PTY writer.
    let (tx_in, rx_in) = unbounded::<Vec<u8>>();

    // Thread that reads stdin (simulating xterm.js keystrokes) and sends bytes to PTY thread.
    // This sends raw bytes, so control sequences and arrows will pass through.
    thread::spawn(move || {
        let mut stdin = std::io::stdin();
        let mut buf = [0u8; 4096];
        loop {
            match stdin.read(&mut buf) {
                Ok(0) => break,
                Ok(n) => {
                    // Forward raw bytes (including \n, \r, escape sequences, etc.)
                    if tx_in.send(buf[..n].to_vec()).is_err() {
                        break;
                    }
                }
                Err(_) => break,
            }
        }
    });

    // PTY loop (single owner of session): multiplex writes + reads.
    pty_loop(&mut session, rx_in)?;
    Ok(())
}

fn pty_loop(session: &mut Session, rx_in: crossbeam_channel::Receiver<Vec<u8>>) -> Result<()> {
    let mut stdout = std::io::stdout();
    let mut buf = [0u8; 8192];

    loop {
        // 1) Drain any pending input quickly so interactive TUIs feel responsive.
        //    Use try_recv in a loop to batch writes.
        while let Ok(chunk) = rx_in.try_recv() {
            // Write raw bytes to the PTY.
            // Using write_all on the Session is fine; it writes to the PTY master.
            if let Err(e) = session.write_all(&chunk) {
                eprintln!("write to pty failed: {e}");
                return Ok(());
            }
            let _ = session.flush();
        }

        // 2) Read PTY output with timeout (configured via set_read_timeout).
        //    With timeout, read() may return an error (WouldBlock/TimedOut) when no data.
        match session.read(&mut buf) {
            Ok(0) => {
                // EOF: child exited.
                eprintln!("\n[child exited]");
                return Ok(());
            }
            Ok(n) => {
                // Forward to our stdout (simulating Tauri event emission).
                stdout.write_all(&buf[..n])?;
                stdout.flush()?;
            }
            Err(e) => {
                // On read timeout / would-block, just continue to process input.
                // Unfortunately the exact error kind can vary across platforms.
                // Treat all read errors as non-fatal unless the input channel is disconnected.
                if rx_in.is_disconnected() {
                    return Ok(());
                }

                // Small sleep prevents a tight loop when idle.
                // (read_timeout already helps, but this keeps CPU low even if error kind differs.)
                thread::sleep(Duration::from_millis(5));

                // Ignore and keep looping.
                let _ = e;
            }
        }

        // 3) Block briefly waiting for either input or just continue.
        // This reduces CPU usage when the child is idle and no user input.
        select! {
            recv(rx_in) -> msg => {
                if let Ok(chunk) = msg {
                    let _ = session.write_all(&chunk);
                    let _ = session.flush();
                } else {
                    // input side closed
                    return Ok(());
                }
            }
            default(Duration::from_millis(5)) => {}
        }
    }
}
"
}

