    let high_cardinality: bool = env::var("HIGH_CARDINALITY")
        .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
        .unwrap_or(false);

    eprintln!("Sending DogStatsD metrics via unix socket: {socket_path}");
    eprintln!("QUEUE_SIZE={qsize} WORKERS={workers} RATE(per worker)={rate_per_worker} HIGH_CARDINALITY={high_cardinality}");

    let client = Arc::new(build_client(&socket_path, qsize)?);

    let sent = Arc::new(AtomicU64::new(0));
    let start = Instant::now();

    for wid in 0..workers {
        let c = Arc::clone(&client);
        let sent = Arc::clone(&sent);

        thread::spawn(move || {
            let interval = if rate_per_worker == 0 {
                Duration::from_secs(0)
            } else {
                Duration::from_nanos(1_000_000_000u64 / rate_per_worker)
            };

            let mut next = Instant::now();
            loop {
