                let _ = c
                    .incr_with_tags("operations.count")
                    .with_tag("client_name", &client_name)
                    .with_tag("client_version", &client_version)
                    .with_tag("network", network)
                    .with_tag("query", &query)
                    .with_tag("runtime", "rust")
                    .try_send();

                sent.fetch_add(1, Ordering::Relaxed);

                if interval.as_nanos() > 0 {
                    next += interval;
                    let now = Instant::now();
                    if next > now {
                        thread::sleep(next - now);
                    } else {
                        // If we're behind, reset schedule to avoid runaway tight loop.
                        next = now;
                    }
