        let n = sent.load(Ordering::Relaxed);
        let elapsed = start.elapsed().as_secs_f64();
        let r = n as f64 / elapsed.max(1e-9);
        eprintln!("sent={} avg_rate={:.0}/sec", n, r);
    }
