  "main.rs": "use std::{
    future::Future,
    pin::Pin,
    sync::mpsc::{self, Sender},
};

pub struct Context(i32);

pub enum InnerAsyncEvent {
    DoWithContext {
        // A boxed HRTB closure: for any borrow of Context, return a Send future
        block: Box<
            dyn for<'a> Fn(&'a mut Context) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
                + Send
                + 'static,
        >,
    },
}

/// Convenience helper: accept a normal (non-async) closure that *returns* an async future.
///
/// This is the stable way to express "async closure"-like ergonomics with Send.
pub fn with_context_async<F, Fut>(work_sender: &Sender<InnerAsyncEvent>, f: F)
where
    // for any lifetime 'a, take &'a mut Context and produce a future that may borrow it
    F: for<'a> FnOnce(&'a mut Context) -> Fut + Send + 'static,
    // and that future must be Send for any 'a
    Fut: for<'a> Future<Output = ()> + Send + 'a,
{
    // We need to store something callable multiple times in the enum, so we adapt FnOnce into Fn
    // by moving it into an Option and taking it on first call.
    let mut f = Some(f);

    let _ = work_sender.send(InnerAsyncEvent::DoWithContext {
        block: Box::new(move |ctx: &mut Context| {
            let f = f.take().expect("event invoked more than once");
            Box::pin(f(ctx))
        }),
    });
}

#[tokio::main]
async fn main() {
    let (tx, rx) = mpsc::channel::<InnerAsyncEvent>();

    // This looks very close to an async closure at the call site.
    // (We write a closure returning an `async move { ... }` block.)
    with_context_async(&tx, |ctx: &mut Context| async move {
        ctx.0 += 1;
    });

    let event = rx.recv().unwrap();

    tokio::spawn(async move {
        let mut ctx = Context(0);
        let fut = match event {
            InnerAsyncEvent::DoWithContext { block } => block(&mut ctx),
        };
        fut.await;
        println!("ctx.0 = {}", ctx.0);
    })
    .await
    .unwrap();
}
"
