use opentelemetry::{global, trace::TraceContextExt};
use opentelemetry_sdk::trace as sdktrace;
use tracing::{info, Instrument};
use tracing_opentelemetry::OpenTelemetrySpanExt;

/// Context that lives for the whole request lifecycle.
///
/// Key idea:
/// - store a `tracing::Span` (the parent span)
/// - later, in callbacks on any task/thread, re-enter that span
///   or instrument futures with it.
#[derive(Clone)]
struct RequestCtx {
    parent: tracing::Span,
}

#[tokio::main(flavor = "multi_thread", worker_threads = 2)]
async fn main() {
    // --- OpenTelemetry pipeline + tracing subscriber wiring ---
    let exporter = opentelemetry_stdout::SpanExporter::default();
    let provider = sdktrace::TracerProvider::builder()
        .with_simple_exporter(exporter)
        .build();

    let tracer = provider.tracer("rehydrate-span-demo");
    global::set_tracer_provider(provider);

    let otel_layer = tracing_opentelemetry::layer().with_tracer(tracer);

    tracing_subscriber::registry()
        .with(tracing_subscriber::EnvFilter::new("info"))
        .with(tracing_subscriber::fmt::layer())
        .with(otel_layer)
        .init();

    // Simulate a single request. In real Pingora, this context would be stored
    // in the request/session struct and passed to stage callbacks.
    let ctx = Arc::new(make_request_ctx());

    // Stage 1 runs now on this task
    stage_1(ctx.clone()).await;

    // Stage 2 is called back later and maybe on a different runtime worker.
    // We'll spawn it to simulate that.
    let t2 = tokio::spawn(stage_2(ctx.clone()));

    // Another callback later.
    let t3 = tokio::spawn(upstream(ctx.clone()));

    let _ = tokio::join!(t2, t3);

    // Ensure exporter flushes.
    global::shutdown_tracer_provider();
}

fn make_request_ctx() -> RequestCtx {
    // Create the parent span for the whole request.
    // IMPORTANT: also set the OpenTelemetry parent context correctly.
    // Here it's a root span; in a real proxy, you'd extract remote context
    // from incoming headers and call `span.set_parent(remote_ctx)`.
    let parent = tracing::info_span!(
        "request",
        http.method = "GET",
        http.route = "/",
        request.id = 123
    );

    // (Optional) If you had a remote context:
    // let remote_ctx: opentelemetry::Context = ...;
    // parent.set_parent(remote_ctx);

    RequestCtx { parent }
}

async fn stage_1(ctx: Arc<RequestCtx>) {
    // Re-enter the parent span for this synchronous section (so logs/events
    // and any child spans become children of `request`).
    let _guard = ctx.parent.enter();

    // Create stage span as a child of the currently entered parent span.
    let stage = tracing::info_span!("stage_1", work = "parse_request");
    let _stage_guard = stage.enter();

    info!("stage 1 doing some work");
    tokio::time::sleep(Duration::from_millis(50)).await;
}

async fn stage_2(ctx: Arc<RequestCtx>) {
    // This could run on any thread/task.
    // Ensure parent is active for this callback.
    // Using `.instrument(ctx.parent.clone())` propagates the span across await
    // points inside this future.
    async move {
        let stage = tracing::info_span!("stage_2", work = "authz");

        async {
            info!("stage 2 doing some work");
            tokio::time::sleep(Duration::from_millis(80)).await;

            // Demonstrate that OTEL context is also correctly available when
            // using tracing-opentelemetry.
            let otel_cx = tracing::Span::current().context();
            let span_ctx = otel_cx.span().span_context().clone();
            info!(trace_id = %span_ctx.trace_id(), span_id = %span_ctx.span_id(), "current otel ids");
        }
        .instrument(stage)
        .await;
    }
    .instrument(ctx.parent.clone())
    .await
}

async fn upstream(ctx: Arc<RequestCtx>) {
    // Another callback, also potentially on another thread.
    // Here we show the alternate pattern: explicit `enter()`.
    let _guard = ctx.parent.enter();

    let upstream = tracing::info_span!("upstream", peer = "example.com:443");
    let _up_guard = upstream.enter();

    info!("calling upstream");
    tokio::time::sleep(Duration::from_millis(30)).await;

    info!("upstream done");
}
