// A tiny PRNG that's usable in const contexts.
// This is SplitMix64 (public domain, widely used to seed other generators).
// For Zobrist hashing you only need deterministic, well-distributed 64-bit values;
// you do not need a cryptographically-secure RNG.
const fn splitmix64_next(state: &mut u64) -> u64 {
    // SplitMix64 step
    *state = state.wrapping_add(0x9E3779B97F4A7C15);
    let mut z = *state;
    z ^= z >> 30;
    z = z.wrapping_mul(0xBF58476D1CE4E5B9);
    z ^= z >> 27;
    z = z.wrapping_mul(0x94D049BB133111EB);
    z ^ (z >> 31)
}

