  "main.rs": "use thiserror::Error;

// --- A tiny "framework" error type for the demo ---
#[derive(Debug, Error)]
pub enum FrameworkError {
    #[error("400: {0}")]
    Error400(Box<dyn std::error::Error + Send + Sync>),
}

// --- Library code ---
pub mod my_library {
    pub mod extensions {
        pub mod logging {
            use crate::FrameworkError;

            // Key idea:
            // We can't make `log::warn!` pretend it was invoked from the caller's module.
            // `module_path!()` is a compile-time macro evaluated at the invocation site.
            // Here, the invocation site is this library module.
            //
            // Workaround:
            // *Use a custom log target* and pass the caller's `module_path!()` from a macro.
            // `env_logger` will print that `target` as the module-ish field.
            //
            // This provides the behavior you want in practice: logs show the *calling module*.

            pub trait LogChangeErrForRespExt {
                type R;

                // Helper that takes caller module path as argument.
                // Users won't call this directly; the macro below will.
                #[track_caller]
                fn log_and_explain_400_with_target(self, caller_module: &'static str) -> Self::R;
            }

            impl<T, E> LogChangeErrForRespExt for Result<T, E>
            where
                E: std::error::Error + Send + Sync + 'static,
            {
                type R = Result<T, FrameworkError>;

                #[track_caller]
                fn log_and_explain_400_with_target(self, caller_module: &'static str) -> Self::R {
                    match self {
                        Ok(ok) => Ok(ok),
                        Err(err) => {
                            let loc = std::panic::Location::caller();
                            // Use caller module as the *target*, so it shows up in env_logger output.
                            log::warn!(
                                target: caller_module,
                                "real location is {}:{}: Error: {err:?}",
                                loc.file(),
                                loc.line(),
                            );
                            Err(FrameworkError::Error400(Box::new(err)))
                        }
                    }
                }
            }

            // Export a macro that looks like a method call and captures the caller's module.
            // Usage:
            //   log_and_explain_400!(expr)
            // This preserves chaining ergonomics via parentheses:
            //   (failing().pipe?)  -> e.g. `log_and_explain_400!(failing())?`
            #[macro_export]
            macro_rules! log_and_explain_400 {
                ($expr:expr) => {{
                    use $crate::my_library::extensions::logging::LogChangeErrForRespExt as _;
                    ($expr).log_and_explain_400_with_target(module_path!())
                }};
            }
        }
    }
}

// --- Application code ---
pub mod my_application_code {
    pub mod routes_example {
        fn failing_function() -> Result<u32, std::num::ParseIntError> {
            "abc".parse()
        }

        pub fn some_route() -> Result<u32, crate::FrameworkError> {
            log::warn!("This log call is from the correct module");

            // The macro captures this module path (my_application_code::routes_example)
            // and passes it as log target, so env_logger displays it.
            let long_chain = crate::log_and_explain_400!(failing_function())? + 42;

            Ok(long_chain)
        }
    }
}

fn main() {
    env_logger::builder()
        .filter_level(log::LevelFilter::Info)
        .init();

    let failure = my_application_code::routes_example::some_route();
    println!("{failure:?}");
}
