        let hexstr = hexstr.trim();
        hex::decode(hexstr).context("failed to decode hex input")?
    } else {
        fs::read(&arg).with_context(|| format!("failed to read file: {arg}"))?
    };

    // 1) Decode outer CMS ContentInfo
    let ci = ContentInfo::from_der(&body).context("decoding ContentInfo failed")?;
    println!("ContentInfo content_type OID = {}", ci.content_type);

    // 2) IMPORTANT: SCEP PKIOperation commonly uses BER with *indefinite length*
    //    inside fields (notably the eContent OCTET STRING).
    //    The `cms` crate expects DER, so attempting to decode SignedData often fails.
    //
    //    This program demonstrates the usual failure mode, and prints enough
