            Ok(())
        }
        Err(e) => {
            println!("SignedData decode failed (expected with SCEP BER/indefinite-length inputs):\n  {e:?}\n");

            // Helpful diagnostics: show the first bytes of the embedded content
            // (this is the DER/BER encoding of SignedData).
            let raw = ci.content.as_bytes();
            println!("Embedded content length: {} bytes", raw.len());
            println!("Embedded content first 32 bytes: {}", hex::encode(&raw[..raw.len().min(32)]));

            // Minimal BER/DER header hint: first byte should be SEQUENCE (0x30)
            // for SignedData. If it's not, content isn't SignedData.
            if raw.first().copied() != Some(0x30) {
                println!("Note: embedded content does not start with 0x30 (SEQUENCE). It starts with {:?}", raw.first());
            } else {
                println!("Embedded content starts with SEQUENCE (0x30), so it likely is SignedData but not DER-compliant.");
            }

            // Also show ContentInfo version if present (it isn't for ContentInfo),
            // but SignedData has version; we can't decode it here.
            println!("\nNext step (not implemented here): convert BER->DER (definite lengths) before feeding to cms/der decoders.");

            Err(anyhow!("cannot decode SignedData from this input with cms/der (likely BER/indefinite lengths)"))
        }
    }
