fn dump_signed_data(sd: &SignedData) -> Result<()> {
    println!("SignedData.version = {:?}", sd.version);

    println!("digest_algorithms count = {}", sd.digest_algorithms.0.len());
    for (i, alg) in sd.digest_algorithms.0.iter().enumerate() {
