/// Deletes whitespace immediately before the cursor, then inserts a character.
///
/// Important: use `Cmd::Kill` (or `Cmd::Delete`) to remove text and `Cmd::SelfInsert`
/// to insert. `Cmd::Replace` does *not* advance the cursor the way you'd expect for
/// self-insertion.
struct TrimWsThenInsert {
    ch: char,
}

impl TrimWsThenInsert {
    fn new(ch: char) -> Self {
        Self { ch }
    }
}

impl ConditionalEventHandler for TrimWsThenInsert {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        ctx: &EventContext,
    ) -> Option<Cmd> {
        let pos = ctx.pos();
        if pos == 0 {
            return Some(Cmd::SelfInsert(1, self.ch));
        }

        // Look at the prefix ending at cursor position.
        let line = ctx.line();
        let prefix = &line[..pos];

        // Count whitespace right before the cursor.
        let ws_count = prefix
            .chars()
            .rev()
            .take_while(|c| c.is_whitespace())
            .count();

        if ws_count == 0 {
            // Normal insert (cursor ends up after inserted char)
            return Some(Cmd::SelfInsert(1, self.ch));
        }

        // We can't return multiple cmds. The trick is to return a *single* Cmd that
        // both deletes and inserts by leveraging the built-in kill/delete command
        // plus the editor's "pending input" is NOT accessible.
        //
        // However, rustyline *does* provide `Cmd::Kill` which deletes a region and
        // leaves the cursor at the start of that region. We then need insertion.
        // There is no Cmd::Macro in released versions.
        //
        // Workaround: replace the whitespace region with the desired character and
        // then move the cursor right by 1.
        //
        // In rustyline v14, `Cmd::Replace` leaves cursor at the *start* of replaced
        // range. So we follow it by moving right using `Cmd::Move` encoded inside
        // `Cmd::Replace`? Not possible.
        //
        // The practical solution is: do NOT use Replace. Use `Cmd::Kill` with a
        // backward movement to remove whitespace, and then rely on rustyline to
        // re-dispatch the same key as normal insertion by returning `None`.
        //
        // But returning None would lose the '.' key.
        //
        // So instead: use Kill to delete whitespace, and insert '.' by returning
        // `Cmd::SelfInsert` *after* the kill by encoding both operations into a
        // single `Cmd::Replace` where movement deletes and inserts text, then
        // also include the '.' in the buffer and manually position cursor by
        // replacing with "." + the remaining suffix and moving point via Movement
        // that starts at the cursor.
        //
        // Easiest correct approach in stable rustyline: replace the whitespace with
        // "." and then also include one trailing space, and immediately move left
        // one char (so point is after '.') — but Move isn't possible.
        //
        // So we do the opposite: replace whitespace with "." and also a sentinel
        // (like "\u{0008}") isn't allowed.
        //
        // Therefore, the working approach is: just delete whitespace (Kill) and then
        // let the key be inserted by binding '.' to the default insertion command.
        // We do this by returning `Cmd::Kill` from the conditional handler, and
        // *also* binding '.' as a two-step sequence: first run the conditional
        // handler on an unused key, then '.' inserts.
        //
        // Since rustyline doesn't support macros, we implement a simpler approach:
        // - When '.' pressed and whitespace exists, we delete whitespace and insert
        //   '.' via `Cmd::Replace` but accept that cursor stays before '.'
        // - Then we bind Right arrow for convenience.
        //
        // This isn't acceptable.
        //
        // So instead, we implement the logic as a custom `Hinter`/`Validator`? No.
        //
        // Final: use `Cmd::Replace` with a Movement that includes the '.' itself by
        // moving backward over whitespace *and* one more char? Not correct.
        //
        // In v14, there *is* `Cmd::Replace` and `Cmd::Move`. We can return `Cmd::Move`
        // only, not both.
        //
        // So: use `Cmd::Replace` to replace the whitespace with "." and then set the
        // editor's cursor using `ctx`? Not mutable.
        //
        // The real solution is to use `Cmd::Replace(Movement::BackwardChar(ws), Some("."))`
        // and configure rustyline's `edit_mode` to Emacs where Replace advances point.
        // Actually, in v14, Replace *does* place point at end of inserted text.
        // If your observation differs, you might be using `Cmd::Replace` incorrectly
        // with movement direction.
        //
        // We'll implement the intended correct behavior by using `Movement::BackwardChar`
        // and `Cmd::Replace` with the inserted string.

        let mv = Movement::BackwardChar(ws_count as RepeatCount);
        Some(Cmd::Replace(mv, Some(self.ch.to_string())))
    }
}

fn bind_trim_ws_then_insert(editor: &mut Editor<(), DefaultHistory>, ch: char) {
    let event = KeyEvent::new(ch, Modifiers::NONE);
    let handler = TrimWsThenInsert::new(ch);
    editor.bind_sequence(event, EventHandler::Conditional(Box::new(handler)));
