/// Parse LanceDB-like ISO strings such as:
/// - "1970-01-01T00:00:00"
/// - "2025-08-02T17:35:41.409" (fractional seconds, 3 digits)
/// - "2025-08-02T17:35:41.409123" (fractional seconds, 6 digits)
/// - optionally with timezone: "...Z" or "+00:00"
///
/// Returns a UTC DateTime.
fn parse_lancedb_iso_to_utc(s: &str) -> Result<DateTime<Utc>, chrono::ParseError> {
    // 1) If the string includes an offset (e.g. Z or +00:00), parse as DateTime with offset.
    // RFC3339 requires an offset, so this handles those cases reliably.
    if s.ends_with('Z') || s.contains('+') || (s.rfind('-').map(|i| i > 9).unwrap_or(false)) {
        // The rfind('-') > 9 heuristic avoids treating the date's '-' as an offset sign.
        // It's not perfect, but fine for typical ISO strings.
        if let Ok(dt) = DateTime::parse_from_rfc3339(s) {
            return Ok(dt.with_timezone(&Utc));
        }
        // If it looked like it had an offset but failed RFC3339, fall through to naive parsing.
    }

    // 2) LanceDB examples shown are *naive* (no timezone). Parse those as NaiveDateTime.
    // Use two formats: with optional fraction, and without.
    // In chrono, "%.f" parses 0..9 fractional digits, but it expects the '.' to exist.
    // So we try with fraction first, then without.
    let naive = NaiveDateTime::parse_from_str(s, "%Y-%m-%dT%H:%M:%S%.f")
        .or_else(|_| NaiveDateTime::parse_from_str(s, "%Y-%m-%dT%H:%M:%S"))?;

    Ok(Utc.from_utc_datetime(&naive))
}

