/// Here we return seconds. If you stored milliseconds, use timestamp_millis().
fn date_string_to_unix_seconds(s: &str) -> Result<i64, chrono::ParseError> {
    let dt = parse_lancedb_iso_to_utc(s)?;
    Ok(dt.timestamp())
}

