  "main.rs": "use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll, RawWaker, RawWakerVTable, Waker};
use tokio::time::{sleep, Duration};

/// Result of a single, synchronous poll attempt.
enum TryPollResult<T> {
    Ready(T),
    Pending,
}

/// A waker that does nothing.
///
/// This is enough when you only want to check whether a future is *already ready*
/// without registering for wakeups (if it returns Pending, you will spawn and await it).
fn noop_waker() -> Waker {
    unsafe fn clone(_: *const ()) -> RawWaker {
        RawWaker::new(std::ptr::null(), &VTABLE)
    }
    unsafe fn wake(_: *const ()) {}
    unsafe fn wake_by_ref(_: *const ()) {}
    unsafe fn drop(_: *const ()) {}

    static VTABLE: RawWakerVTable = RawWakerVTable::new(clone, wake, wake_by_ref, drop);

    unsafe { Waker::from_raw(RawWaker::new(std::ptr::null(), &VTABLE)) }
}

/// Poll a future exactly once, synchronously.
///
/// - If it is ready *right now*, returns `Ready(output)`.
/// - If it is not ready, returns `Pending`.
///
/// IMPORTANT: This must only be used as a "fast-path" check.
/// If it returns Pending, you must continue the future in a proper async context
/// (e.g., by spawning a task and awaiting it), otherwise it may never make progress.
fn try_poll<T>(fut: &mut Pin<&mut (dyn Future<Output = T> + Send)>) -> TryPollResult<T> {
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);

    match fut.as_mut().poll(&mut cx) {
        Poll::Ready(v) => TryPollResult::Ready(v),
        Poll::Pending => TryPollResult::Pending,
    }
}

/// Example future that is either immediately ready or becomes ready later.
async fn maybe_immediate(immediate: bool) -> &'static str {
    if immediate {
        "ready immediately"
    } else {
        sleep(Duration::from_millis(200)).await;
        "ready later"
    }
}

/// Non-async function called from an async context.
/// It tries a synchronous poll, and if Pending, spawns a Tokio task to await it.
fn non_async_consumer(immediate: bool) {
    // Create the future.
    let fut = maybe_immediate(immediate);

    // Pin it on the stack so we can poll it.
    tokio::pin!(fut);

    // Use a trait object to make the signature a bit simpler for this demo.
    let mut fut_obj: Pin<&mut (dyn Future<Output = _> + Send)> = fut;

    match try_poll(&mut fut_obj) {
        TryPollResult::Ready(v) => {
            println!("fast path: {v}");
        }
        TryPollResult::Pending => {
            println!("pending: spawning task");
            tokio::spawn(async move {
                let v = fut_obj.await;
                println!("spawned task completed: {v}");
            });
        }
    }
}

#[tokio::main(flavor = "multi_thread")]
async fn main() {
    // Case 1: immediately ready
    non_async_consumer(true);

    // Case 2: not ready, will be handled by spawned task
    non_async_consumer(false);

    // Give the spawned task time to finish in this demo.
    sleep(Duration::from_millis(500)).await;
}
"
