    let n = 4;
    let k = 3;
    let matrix = DMatrix::<f64>::from_row_slice(
        n,
        k,
        &[
            1.0, 2.0, 3.0, // row 0
            4.0, 5.0, 6.0, // row 1
            7.0, 8.0, 9.0, // row 2
            10.0, 11.0, 12.0, // row 3
        ],
    );

