    // Using column_sum() + scaling is explicit and works on DMatrix.
    let mean: RowDVector<f64> = (matrix.column_sum() / (n as f64)).transpose();

    // "Broadcast" mean to all rows by multiplying a column of ones (n x 1)
    // with the mean row vector (1 x k), producing an (n x k) matrix.
    let ones: DVector<f64> = DVector::from_element(n, 1.0);
    let mean_matrix = &ones * &mean; // outer product -> (n x k)

