/// A cached connection consists of:
/// - the Client (used to issue queries)
/// - a JoinHandle for the spawned Connection driver task
///
/// Keeping ONLY Client is not enough: if the spawned task ends (driver stops),
/// the socket is no longer polled and the server will eventually close the connection,
/// and you will see `Error { kind: Closed, .. }` from the Client.
#[derive(Clone)]
struct CachedConn {
    client: Client,
    _driver: Arc<JoinHandle<()>>, // keep the task alive + observable
}

impl CachedConn {
    async fn connect(conn_str: &str) -> Result<Self> {
        let (client, connection) = tokio_postgres::connect(conn_str, NoTls)
            .await
            .context("connect failed")?;

        // IMPORTANT: keep this task alive. If it exits, the connection is effectively dead.
        let driver = tokio::spawn(async move {
            if let Err(e) = connection.await {
                eprintln!("[driver] connection error: {e}");
            }
        });

        Ok(Self {
            client,
            _driver: Arc::new(driver),
        })
    }
}

