const NOTION_DERIVE_LIB_RS: &str = r#"use proc_macro::TokenStream;
use quote::{quote, ToTokens};
use syn::{
    parse_macro_input, spanned::Spanned, Attribute, Data, DeriveInput, Fields, LitStr,
};

#[proc_macro_derive(NotionMap, attributes(notion_property))]
pub fn derive_notion_map(input: TokenStream) -> TokenStream {
    let input = parse_macro_input!(input as DeriveInput);
    let struct_ident = input.ident;

    let data = match input.data {
        Data::Struct(s) => s,
        _ => {
            return syn::Error::new(input.span(), "NotionMap can only be derived for structs")
                .to_compile_error()
                .into();
        }
    };

    let fields = match data.fields {
        Fields::Named(named) => named.named,
        _ => {
            return syn::Error::new(data.fields.span(), "NotionMap requires named fields")
                .to_compile_error()
                .into();
        }
    };

    let mut inserts = Vec::new();

    for field in fields {
        let field_ident = match field.ident {
            Some(i) => i,
            None => continue,
        };

        if let Some((prop_type, prop_name)) = parse_notion_property(&field.attrs) {
            let prop_name_lit = prop_name;

            let insert_tokens = match prop_type.as_str() {
                // String -> Title([RichTextObject { text: {content} }])
                "title" => {
                    quote! {
                        map.insert(
                            #prop_name_lit.to_string(),
                            PropertyValue::Title(vec![RichTextObject { text: TextObject { content: self.#field_ident.clone(), link: None } }]),
                        );
                    }
                }
                // Option<String> -> Url(String) if Some
                "url" => {
                    quote! {
                        if let Some(v) = self.#field_ident.clone() {
                            map.insert(#prop_name_lit.to_string(), PropertyValue::Url(v));
                        }
                    }
                }
                // Option<Vec<Value>> -> MultiSelect(Vec<SelectObject>) if Some
                "multi_select" => {
                    quote! {
                        if let Some(values) = self.#field_ident.as_ref() {
                            let items = values
                                .iter()
                                .map(|f| SelectObject { id: None, color: None, name: format!("{}", f) })
                                .collect();
                            map.insert(#prop_name_lit.to_string(), PropertyValue::MultiSelect(items));
                        }
                    }
                }
                other => {
                    return syn::Error::new(
                        field.span(),
                        format!("Unsupported notion_property type: {other}. Supported: title, url, multi_select"),
                    )
                    .to_compile_error()
                    .into();
                }
            };

            inserts.push(insert_tokens);
        }
    }

    let expanded = quote! {
        impl ToNotionProperties for #struct_ident {
            fn to_notion_properties(&self) -> ::std::collections::HashMap<String, PropertyValue> {
                let mut map: ::std::collections::HashMap<String, PropertyValue> = ::std::collections::HashMap::new();
                #(#inserts)*
                map
            }
        }
    };

    expanded.into()
}

fn parse_notion_property(attrs: &[Attribute]) -> Option<(String, LitStr)> {
    for attr in attrs {
        if !attr.path().is_ident("notion_property") {
            continue;
        }

        // Parse: #[notion_property(type = "title", name = "Name")]
        let mut ty: Option<String> = None;
        let mut name: Option<LitStr> = None;

        let _ = attr.parse_nested_meta(|meta| {
            if meta.path.is_ident("type") {
                let lit: LitStr = meta.value()?.parse()?;
                ty = Some(lit.value());
                return Ok(());
            }
            if meta.path.is_ident("name") {
                let lit: LitStr = meta.value()?.parse()?;
                name = Some(lit);
                return Ok(());
            }
            Ok(())
        });

        if let (Some(t), Some(n)) = (ty, name) {
            return Some((t, n));
        }
    }
    None
}
"#;
"
}

