        let start = line[..pos]
            .rfind(|c: char| c.is_whitespace())
            .map(|i| i + 1)
            .unwrap_or(0);
        let prefix = &line[start..pos];

        let cmds = self.cmds.lock().unwrap();
        let mut out = Vec::new();
        for c in cmds.iter() {
            if c.starts_with(prefix) {
                out.push(c.clone());
            }
        }
        Ok((start, out))
    }
}

fn main() -> anyhow::Result<()> {
