        Command::new("sh")
            .args([
                "-c",
                // Background: print a line every second.
                // Foreground: read stdin lines and echo them.
                "(i=0; while true; do i=$((i+1)); echo \"child-async: tick $i\"; sleep 1; done) & \
                 while IFS= read -r line; do echo \"child-echo: $line\"; done",
            ])
            .stdin(Stdio::piped())
            .stdout(Stdio::piped())
            .stderr(Stdio::piped())
            .spawn()?
