    // We use rl.print() which clears/redraws appropriately.
    let rl_arc = Arc::new(Mutex::new(rl));
    let rl_for_out = rl_arc.clone();
    let out_thread = thread::spawn(move || {
        let mut br = BufReader::new(child_stdout);
        let mut line = String::new();
        while let Ok(n) = br.read_line(&mut line) {
            if n == 0 {
                break;
            }
            let msg = line.trim_end_matches(['\r', '\n']).to_string();
            line.clear();

            // Update completions dynamically as an example.
            if msg.starts_with("child-echo:") {
                if let Ok(mut cmds) = helper_for_thread.cmds.lock() {
                    cmds.push(format!("seen:{}", cmds.len()));
                }
            }

            if let Ok(mut rl) = rl_for_out.lock() {
                // This prints above the current input line and then redraws the prompt.
                let _ = rl.print(format!("{msg}\n"));
            } else {
                // Fallback
                let _ = writeln!(io::stdout(), "{msg}");
                let _ = io::stdout().flush();
            }
        }
    });

    // Thread to read stderr similarly.
    let rl_for_err = rl_arc.clone();
    let err_thread = thread::spawn(move || {
        let mut br = BufReader::new(child_stderr);
        let mut line = String::new();
        while let Ok(n) = br.read_line(&mut line) {
            if n == 0 {
                break;
            }
            let msg = line.trim_end_matches(['\r', '\n']).to_string();
            line.clear();
            if let Ok(mut rl) = rl_for_err.lock() {
                let _ = rl.print(format!("child-stderr: {msg}\n"));
            }
        }
    });

    // Main input loop.
    // Note: readline() blocks, but async output still appears because the output
    // threads call rl.print(), which safely redraws the prompt.
    loop {
        let line = {
            let mut rl = rl_arc.lock().unwrap();
            rl.readline("> ")
