        match line {
            Ok(l) => {
                let trimmed = l.trim();
                {
                    let mut rl = rl_arc.lock().unwrap();
                    let _ = rl.add_history_entry(trimmed);
                }
                if trimmed == "quit" || trimmed == "exit" {
                    break;
                }

                // Send user input to child.
                writeln!(child_stdin, "{trimmed}")?;
                child_stdin.flush()?;
            }
            Err(ReadlineError::Interrupted) => {
                // Ctrl-C
                let mut rl = rl_arc.lock().unwrap();
                let _ = rl.print("^C\n".to_string());
            }
            Err(ReadlineError::Eof) => {
                // Ctrl-D
                break;
            }
            Err(e) => {
                eprintln!("readline error: {e}");
                break;
            }
        }

        // Small sleep to avoid busy looping if something goes wrong with locking.
        thread::sleep(Duration::from_millis(10));
    }

    // Cleanup
    disable_raw_mode().ok();

    // Try to terminate child.
    let _ = child.kill();

    let _ = out_thread.join();
    let _ = err_thread.join();

    Ok(())
