        .get(header::UPGRADE)
        .and_then(|v| v.to_str().ok())
        .is_some_and(|v| v.eq_ignore_ascii_case("websocket"));

    if is_ws_upgrade {
        let origin = req.headers().get(header::ORIGIN).ok_or(StatusCode::FORBIDDEN)?;
