async fn handle(req: Request<hyper::body::Incoming>, root: &Path) -> Response<hyper_body_util::combinators::BoxBody<Bytes, std::io::Error>> {
    // Map URL path to filesystem path (very minimal; production code should harden this).
    let mut rel = req.uri().path().trim_start_matches('/').to_string();
    if rel.is_empty() {
        rel = "index.html".to_string();
    }

    // Prevent obvious path traversal like "../..".
    if rel.contains("..") {
        return simple_response(StatusCode::BAD_REQUEST, "bad path");
    }

    let path: PathBuf = root.join(rel);

    match file_response(&path).await {
        Ok(resp) => resp,
        Err(e) if e.kind() == std::io::ErrorKind::NotFound => {
            simple_response(StatusCode::NOT_FOUND, "not found")
        }
        Err(e) => {
            tracing::warn!("error opening/reading {}: {e}", path.display());
            simple_response(StatusCode::INTERNAL_SERVER_ERROR, "internal error")
        }
    }
}

fn simple_response(
    status: StatusCode,
    msg: &'static str,
) -> Response<hyper_body_util::combinators::BoxBody<Bytes, std::io::Error>> {
    Response::builder()
        .status(status)
        .header(header::CONTENT_TYPE, "text/plain; charset=utf-8")
        .body(http_body_util::Full::new(Bytes::from_static(msg.as_bytes())).map_err(|never| match never {}).boxed())
        .unwrap()
}

async fn file_response(
    path: &Path,
) -> Result<Response<hyper_body_util::combinators::BoxBody<Bytes, std::io::Error>>, std::io::Error> {
    let file = tokio::fs::File::open(path).await?;
    let meta = file.metadata().await.ok();

    // Turn AsyncRead (File) into a Stream of Bytes chunks.
    let byte_stream = ReaderStream::new(file);

    // Turn Stream<Item = Result<Bytes, io::Error>> into a hyper Body by wrapping each chunk into a Frame.
    let frame_stream = byte_stream.map_ok(Frame::data);
    let body = StreamBody::new(frame_stream).boxed();

    let mut builder = Response::builder().status(StatusCode::OK);

    // If we know the length, set Content-Length (lets clients show progress and enables some optimizations).
    if let Some(meta) = meta {
        builder = builder.header(header::CONTENT_LENGTH, meta.len());
    }

    // Minimal content-type guess.
    if let Some(ct) = content_type_from_path(path) {
        builder = builder.header(header::CONTENT_TYPE, ct);
    }

    Ok(builder.body(body).unwrap())
}

fn content_type_from_path(path: &Path) -> Option<&'static str> {
    match path.extension().and_then(|e| e.to_str()).unwrap_or("") {
        "html" => Some("text/html; charset=utf-8"),
        "css" => Some("text/css; charset=utf-8"),
        "js" => Some("application/javascript; charset=utf-8"),
        "json" => Some("application/json; charset=utf-8"),
        "txt" => Some("text/plain; charset=utf-8"),
        "png" => Some("image/png"),
        "jpg" | "jpeg" => Some("image/jpeg"),
        "gif" => Some("image/gif"),
        "svg" => Some("image/svg+xml"),
        _ => None,
    }
}
