fn spin_cube(time: Res<Time>, mut q: Query<&mut Transform, With<Block>>) {
    let mut t = q.single_mut();
    let yaw = Quat::from_rotation_y(0.7 * time.delta_seconds());
    let pitch = Quat::from_rotation_x(0.4 * time.delta_seconds());
    t.rotation = (yaw * pitch) * t.rotation;
}

fn draw_face_gizmo(mut gizmos: Gizmos, q: Query<&Transform, With<Block>>) {
    let block_xf = q.single();

    // --- Simulated ray hit (in LOCAL space of the cube) ---
    // Pretend we always hit the +X face in local coordinates.
    let local_normal = Vec3::X;

    // Convert that to WORLD normal by rotating with the cube's rotation.
    let world_normal = block_xf.rotation * local_normal;

    // Face center in world space (+X face): local offset is +0.5 on X, rotated into world.
    let face_center = block_xf.translation + (block_xf.rotation * (local_normal * 0.5));

    // We want a rectangle gizmo that:
    // 1) is flush to the face, i.e. its plane is perpendicular to `world_normal`.
    //    (For a rect gizmo lying in XY plane by default, its +Z is the plane normal.)
    // 2) rotates "with" the cube around that normal (so it doesn't look arbitrary).
    //
    // Approach:
    // - Start with the cube's rotation as the baseline orientation.
    // - Compute what direction the rect's +Z would be after that baseline.
    // - Apply an extra rotation (arc) to align that baseline +Z to the required world_normal.
    // - Compose: correction * baseline.

    let baseline = block_xf.rotation;
    let baseline_z = baseline * Vec3::Z;

    // Correction to rotate baseline_z onto world_normal.
    // (If they're already aligned, this is identity.)
    let correction = Quat::from_rotation_arc(baseline_z.normalize(), world_normal.normalize());

    let gizmo_rot = correction * baseline;

    // Draw the face rectangle slightly off the surface to avoid z-fighting.
    let offset = world_normal * 0.01;

    gizmos.rect(
        Isometry3d {
            translation: (face_center + offset).into(),
            rotation: gizmo_rot,
        },
        Vec2::splat(1.0),
        Color::WHITE,
    );

    // Also draw the world normal for clarity.
    gizmos.arrow(face_center, face_center + world_normal * 0.75, Color::YELLOW);
}
