  "main.rs": "use futures::StreamExt;
use std::sync::{Arc, Weak};
use tokio::sync::broadcast::{self, Sender};
use tokio_stream::wrappers::BroadcastStream;

#[derive(Debug, Clone)]
struct Event(u64);

#[derive(Debug)]
struct RecvError;

/// Factory + shutdown handle
fn events_channel(capacity: usize) -> (EventSender, EventStreamFactory, Shutdown) {
    let (tx, _) = broadcast::channel(capacity);
    let shared = Arc::new(Shared { tx });
    let sender = EventSender {
        inner: Arc::downgrade(&shared),
    };
    let factory = EventStreamFactory {
        inner: Arc::clone(&shared),
    };
    let shutdown = Shutdown { inner: shared };
    (sender, factory, shutdown)
}

struct Shared {
    tx: Sender<Event>,
}

/// A clonable sender handle that does *not* keep the underlying broadcast::Sender alive.
/// When Shutdown is triggered, Shared is dropped and all future sends/subscribes become no-ops.
#[derive(Clone, Debug)]
struct EventSender {
    inner: Weak<Shared>,
}

impl EventSender {
    fn send(&self, event: Event) {
        if let Some(shared) = self.inner.upgrade() {
            let _ = shared.tx.send(event);
        }
    }
}

struct EventStreamFactory {
    inner: Arc<Shared>,
}

impl EventStreamFactory {
    fn all_events(
        &self,
    ) -> impl futures::Stream<Item = Result<Event, RecvError>> + Send + 'static {
        BroadcastStream::new(self.inner.tx.subscribe()).filter_map(|event| async move {
            match event {
                Ok(e) => Some(Ok(e)),
                Err(_) => Some(Err(RecvError)),
            }
        })
    }
}

/// Dropping this (or calling shutdown()) drops the last strong Arc holding the sender.
/// That closes the broadcast channel, causing all BroadcastStreams to end.
struct Shutdown {
    inner: Arc<Shared>,
}

impl Shutdown {
    fn shutdown(self) {
        // dropping self is enough
    }
}

#[tokio::main]
async fn main() {
    let (sender, factory, shutdown) = events_channel(16);

    // Spawn a couple of "SSE clients" consuming BroadcastStream
    let mut stream1 = factory.all_events();
    let client1 = tokio::spawn(async move {
        println!("client1: connected");
        while let Some(item) = stream1.next().await {
            match item {
                Ok(Event(n)) => println!("client1: event {n}"),
                Err(_) => println!("client1: recv error"),
            }
        }
        println!("client1: stream ended (channel closed)");
    });

    let mut stream2 = factory.all_events();
    let client2 = tokio::spawn(async move {
        println!("client2: connected");
        while let Some(item) = stream2.next().await {
            match item {
                Ok(Event(n)) => println!("client2: event {n}"),
                Err(_) => println!("client2: recv error"),
            }
        }
        println!("client2: stream ended (channel closed)");
    });

    // Producer task holds only Weak handles (clones don't prevent shutdown)
    let producer_sender = sender.clone();
    let producer = tokio::spawn(async move {
        for n in 0.. {
            producer_sender.send(Event(n));
            tokio::time::sleep(std::time::Duration::from_millis(300)).await;
        }
    });

    println!("Press Ctrl+C to shutdown...");
    let _ = tokio::signal::ctrl_c().await;

    // This is the key: drop the one strong Arc that owns the broadcast::Sender.
    // All BroadcastStreams will observe closure and terminate.
    shutdown.shutdown();

    // Give tasks a moment to notice closure
    tokio::time::sleep(std::time::Duration::from_millis(200)).await;

    // Producer may still be looping but sends are now no-ops because Weak can't upgrade.
    producer.abort();

    let _ = client1.await;
    let _ = client2.await;

    println!("shutdown complete");
}
"
